INSERT INTO `note_1` (`id`, `user_id`, `title`, `content`, `tags`, `summary`, `pinned`, `review_state`, `next_review_at`, `last_reviewed_at`, `create_time`, `update_time`) VALUES
  (1101, 1, '四月产品发布清单', '梳理发布前需要完成的文案、引导页截图、站内公告和回滚方案。重点确保注册流程、欢迎页和通知文案在同一版本内上线。', '发布,项目管理,协作', '一份围绕四月版本上线的执行清单，重点是文案、截图和回滚准备。', 1, 'REVIEW', '2026-03-14 10:00:00', '2026-03-12 09:00:00', '2026-03-08 09:00:00', '2026-03-12 10:30:00'),
  (1102, 1, '周会纪要：注册转化漏斗', '记录本周运营、设计和产品同步的结论：新用户引导页点击率偏低，注册完成率在移动端仍有明显损耗，需要把验证步骤和展示顺序拆开看。', '周会,增长,数据', '会议聚焦注册漏斗下滑问题，决定拆分移动端验证流程并跟踪引导页点击率。', 0, 'NEW', NULL, NULL, '2026-03-09 11:00:00', '2026-03-11 16:20:00'),
  (1103, 1, '客户访谈洞察', '本周访谈了三位已付费用户，大家对仪表盘有兴趣，但更在意每天进入系统后第一眼该做什么。需要把首页做得更像工作台，而不是数据陈列。', '客户研究,需求,访谈', NULL, 0, 'EVERGREEN', '2026-03-18 19:30:00', '2026-03-10 18:20:00', '2026-03-10 18:20:00', '2026-03-12 08:50:00'),
  (1501, 5, '论文相关工作阅读笔记', '整理了三篇与知识管理和任务推荐相关的论文，主要对比建模方法、特征选择和实验设置。后续要补一个自己的文献矩阵。', '论文,阅读,研究', '总结了三篇相关工作论文的模型思路和实验设计，为后续文献矩阵做准备。', 1, 'EVERGREEN', '2026-03-20 20:00:00', '2026-03-11 21:00:00', '2026-03-06 20:30:00', '2026-03-11 21:00:00'),
  (1502, 5, '实验设计待确认假设', '准备验证知识提示对任务完成率的影响。当前还需要确认样本量估算、实验周期和分组方式，避免后面返工。', '实验,研究设计,待办', '记录实验设计还未敲定的三项关键假设：样本量、周期和分组方式。', 0, 'REVIEW', '2026-03-15 14:00:00', '2026-03-12 09:30:00', '2026-03-09 09:30:00', '2026-03-12 09:30:00'),
  (1503, 5, '导师会议纪要 03-11', '导师建议先缩小问题范围，把用户画像收敛到重度记录型用户，再把实验部分从三组降成两组。第三章结构也要更明确。', '导师会议,论文,修改', NULL, 0, 'REVIEW', '2026-03-16 20:30:00', NULL, '2026-03-11 15:10:00', '2026-03-11 18:40:00'),
  (1504, 5, '数据清洗问题备忘', '需要统一空值处理策略，并补一份异常值日志，避免实验结果在复现时出现偏差。当前最容易出问题的是时间字段格式不统一。', '数据分析,清洗,Python', '汇总了数据清洗环节的风险点，重点是空值、异常值和时间格式。', 0, 'NEW', NULL, NULL, '2026-03-12 08:10:00', '2026-03-12 08:55:00');
INSERT INTO `note_2` (`id`, `user_id`, `title`, `content`, `tags`, `summary`, `pinned`, `review_state`, `next_review_at`, `last_reviewed_at`, `create_time`, `update_time`) VALUES
  (1201, 2, 'RocketMQ 异步任务改造记录', '把摘要、整理、提取任务、周复盘统一改成作业模型，note-service 只负责入库和派发，ai-service 负责消费并回写结果。下一步是补失败重试和死信队列。', '后端,RocketMQ,异步', '记录了 AI 作业异步化的实现思路：作业入库、消息投递、消费回写和后续可靠性规划。', 1, 'EVERGREEN', '2026-03-20 11:00:00', '2026-03-12 10:00:00', '2026-03-07 09:20:00', '2026-03-12 10:00:00'),
  (1202, 2, 'Redis 登录态排查', '排查过程中确认 token 失效大多来自开发环境重启 Redis，解决方式是脚本层面避免无脑覆盖本机实例，并在清库后清理 token 键。', 'Redis,鉴权,排障', '总结了登录态失效的主要原因和处理策略，重点在 Redis 重启与 token 键管理。', 0, 'REVIEW', '2026-03-14 16:00:00', '2026-03-11 22:00:00', '2026-03-09 20:20:00', '2026-03-11 22:00:00'),
  (1203, 2, '本周接口联调清单', '还有三项接口需要重点验证：AI 作业状态轮询、来源任务完成后的行为回写、周复盘在首页展示的空状态。', '接口联调,测试,发布', NULL, 0, 'NEW', NULL, NULL, '2026-03-11 09:30:00', '2026-03-12 09:10:00'),
  (1204, 2, 'ShardingSphere 分表注意事项', '当前 note 按 user_id 分表，ai_workflow_job 走 SINGLE 规则。后续如果任务也分表，需要提前梳理跨表统计和 dashboard 聚合方式。', '数据库,ShardingSphere,分表', '沉淀了 note 分表和 ai_workflow_job 单表规则的注意事项，为后续扩展做准备。', 0, 'EVERGREEN', '2026-03-19 18:30:00', '2026-03-10 20:10:00', '2026-03-08 18:00:00', '2026-03-10 20:10:00');
INSERT INTO `note_3` (`id`, `user_id`, `title`, `content`, `tags`, `summary`, `pinned`, `review_state`, `next_review_at`, `last_reviewed_at`, `create_time`, `update_time`) VALUES
  (1301, 3, '本周力量训练复盘', '本周上肢训练状态不错，卧推重量回到稳定水平，但下肢训练因为睡眠不足受影响。下周要把训练安排回到固定时间段。', '健身,训练,复盘', '总结了本周训练强度和恢复情况，下一步是稳定训练时间并补下肢训练。', 1, 'REVIEW', '2026-03-13 20:00:00', '2026-03-12 07:10:00', '2026-03-07 07:00:00', '2026-03-12 07:10:00'),
  (1302, 3, '三天备餐清单', '本周准备鸡胸、冷冻西兰花、鸡蛋和燕麦，尽量把工作日晚饭准备前移，避免临时点外卖。', '饮食,备餐,效率', '一份围绕工作日饮食控制的备餐清单，目标是减少临时点外卖。', 0, 'NEW', NULL, NULL, '2026-03-09 21:30:00', '2026-03-11 19:10:00'),
  (1303, 3, '睡眠和恢复观察', '最近两周在连续加班时，睡眠时长降到六小时以下，第二天训练动作控制明显变差。需要建立更稳定的睡前例行流程。', '睡眠,恢复,习惯', NULL, 0, 'EVERGREEN', '2026-03-19 22:00:00', NULL, '2026-03-10 22:10:00', '2026-03-12 06:50:00');
INSERT INTO `note_0` (`id`, `user_id`, `title`, `content`, `tags`, `summary`, `pinned`, `review_state`, `next_review_at`, `last_reviewed_at`, `create_time`, `update_time`) VALUES
  (1401, 4, '下周短视频选题池', '围绕效率工具、知识整理和低成本自律这三个方向准备下周内容，每条选题都要有明确钩子和一句话价值点。', '内容创作,短视频,选题', '整理了下周内容选题和切入角度，重点是明确钩子和一句话价值点。', 1, 'REVIEW', '2026-03-14 09:30:00', '2026-03-12 08:00:00', '2026-03-08 13:20:00', '2026-03-12 08:00:00'),
  (1402, 4, '直播脚本开场模板', '尝试把开场控制在 20 秒内，先讲今天能解决的问题，再给一个具体案例，最后再介绍自己。', '直播,脚本,表达', '沉淀了一套更短更直接的直播开场模板，用来提升开播前两分钟留存。', 0, 'EVERGREEN', '2026-03-21 20:30:00', '2026-03-10 20:15:00', '2026-03-07 20:15:00', '2026-03-10 20:15:00'),
  (1403, 4, '三月品牌合作跟进', '本月有两个品牌合作在推进，需要确认发布时间窗口、素材交付要求和报价表版本。还要同步近期账号数据给品牌方。', '商务,合作,跟进', NULL, 0, 'NEW', NULL, NULL, '2026-03-11 14:20:00', '2026-03-12 11:00:00'),
  (1404, 4, '封面文案 A/B 测试观察', '同一主题下，结论型封面在收藏率上更好，问题型封面更适合拉点击。后续要按内容类型区分。', '文案,封面,测试', '记录了封面文案测试的阶段性结论：问题型提点击，结论型提收藏。', 0, 'REVIEW', '2026-03-15 18:00:00', '2026-03-11 18:20:00', '2026-03-09 18:20:00', '2026-03-11 18:20:00');
