  (12, 3, '晚上 11 点前上床', '连续五天把睡眠拉回 7 小时以上。', '2026-03-16 23:00:00', '睡眠,习惯', NULL, 1, '2026-03-12 06:55:00'),
  (13, 3, '记录本周睡眠时长', '用备忘录记录入睡时间和起床精神状态。', '2026-03-15 08:00:00', '睡眠,追踪', 1303, 0, '2026-03-12 06:58:00'),
