  (16, 4, '整理封面点击率数据', '把最近十条视频的封面表现拉到同一张表里。', '2026-03-15 15:00:00', '文案,测试', 1404, 0, '2026-03-11 18:30:00'),
  (17, 4, '回复品牌邮件', '确认素材交付时间和口播要求。', '2026-03-11 19:00:00', '商务,沟通', NULL, 2, '2026-03-11 16:00:00'),
  (18, 5, '补实验样本量估算', '先把最小样本量和招募成本算清楚。', '2026-03-15 18:00:00', '实验,研究设计', 1502, 0, '2026-03-12 09:35:00'),
  (19, 5, '按导师意见修改第三章', '先收缩研究问题，再把章节结构调顺。', '2026-03-16 22:00:00', '论文,修改', 1503, 1, '2026-03-11 18:45:00'),
